#include <stdio.h>
#include <stdlib.h>

int compare_int(const void *a, const void *b) {
    return (*(int *)a) - (*(int *)b);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *a = (int *)malloc(sizeof(int) * n);
        int *b = (int *)malloc(sizeof(int) * m);
        for (int i = 0; i < n; ++i) scanf("%d", &a[i]);
        for (int i = 0; i < m; ++i) scanf("%d", &b[i]);
        qsort(a, n, sizeof(int), compare_int);
        qsort(b, m, sizeof(int), compare_int);
        int *res = (int *)malloc(sizeof(int) * (n < m ? n : m));
        int i = 0, j = 0, k = 0;
        while (i < n && j < m) {
            if (a[i] == b[j]) {
                res[k++] = a[i];
                ++i; ++j;
            } else if (a[i] < b[j]) {
                ++i;
            } else {
                ++j;
            }
        }
        for (int p = 0; p < k; ++p) {
            if (p) printf(" ");
            printf("%d", res[p]);
        }
        printf("\n");
        free(a);
        free(b);
        free(res);
    }
    return 0;
}

