    while (T--) {
        int n, m;
        cin >> n >> m;
        vector<int> a(n), b(m);
        for (int &x : a) cin >> x;
        for (int &x : b) cin >> x;
        sort(a.begin(), a.end());
        sort(b.begin(), b.end());
        vector<int> ans;
        int i = 0, j = 0;
        while (i < n && j < m) {
            if (a[i] == b[j]) {
                ans.push_back(a[i]);
                ++i; ++j;
            } else if (a[i] < b[j]) {
                ++i;
            } else {
                ++j;
            }
        }
        for (size_t p = 0; p < ans.size(); ++p) {
            if (p) cout << ' ';
            cout << ans[p];
        }
        cout << '\n';
    }
    return 0;
}

