const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const n = input[idx++];
  const m = input[idx++];
  const a = input.slice(idx, idx + n); idx += n;
  const b = input.slice(idx, idx + m); idx += m;
  a.sort((x, y) => x - y);
  b.sort((x, y) => x - y);
  let i = 0, j = 0;
  const res = [];
  while (i < n && j < m) {
    if (a[i] === b[j]) { res.push(a[i]); i++; j++; }
    else if (a[i] < b[j]) i++; else j++;
  }
  outputs.push(res.join(' '));
}
